import ComponentBase from "../../engine/ComponentBase";

 

const { ccclass, property } = cc._decorator;

@ccclass
export default class LoadingIcon extends ComponentBase {

    private icon: cc.Node;
    // private nowColor:number = ;

    onEnable() {
        this.icon = this.findChild(this.node, "icon")
    }

    update() {
        this.icon.angle -= 5;
    }

    onDisable() {

    }
}
 