import BasePlatformAPI from "./BasePlatformAPI";

export default class PayAPI extends BasePlatformAPI {

    private static pay: PayAPI = null;
    public static get Init(): PayAPI {
        if (this.pay == null) {
            this.pay = new PayAPI();
        }
        return this.pay;
    }

    /** 字节支付 */
    public GetTTPay(data: any, _handle: Function = null) {
        if (!this.api) {
            console.error("API null");
            return;
        }
        let _this = this;
        this.api.checkSession({
            success: (res) => {
                if (res.errMsg == "checkSession:ok") {
                    _this.api.requestGamePayment({
                        mode: "game",
                        env: 0,
                        currencyType: "CNY",
                        platform: "android",
                        buyQuantity: data.buyQuantity,
                        zoneId: data.zoneId || 1,
                        customId: data.customId || "",
                        extraInfo: data.extraInfo || "",
                        success: (res) => {
                            console.error("支付成功GEtTTPay", res);
                            _handle && _handle({ succ: true, data: res });
                        },
                        fail: (res) => {
                            console.error("支付失败GEtTTPay", res);
                            _handle && _handle({ succ: false, data: res });
                        }
                    });
                }
            },
            fail: (res) => {
                console.error("支付失败GEtTTPay", res);
                _handle && _handle({ succ: false, data: res });
            }
        });
    }

    /**wx 米大师支付 */
    public GetWxMidasPay(_buyQuantity, _zoneId = 1, _handle = null) {
        if (!this.api) return;
        this.api.requestMidasPayment(
            {
                mode: "game",
                env: 0,
                offerId: "1450047606",
                currencyType: "CNY",
                platform: "android",
                buyQuantity: _buyQuantity,
                zoneId: _zoneId,
                success: (res) => {
                    console.log("succ", res);
                    _handle && _handle({ succ: true, data: res });
                },
                fail: (res) => {
                    console.log("fail", res);
                    _handle && _handle({ succ: false, data: res });
                }
            }
        );
    }

    /**
     * qq 米大师支付
     * @param prepayId 商品预下单获取的预下单id
     * @param starCurrency 金币数 商品预下单时填写的金币数量
     * @param _handle 
     * @returns 
     */
    public GetQqMidasPay(prepayId: any,starCurrency:any,_handle: Function = null) {
        if (!this.api) return;
        this.api.requestMidasPayment(
            {
                prepayId:prepayId,
                starCurrency:starCurrency,
                setEnv:0,
                success: (res) => {
                    console.error("支付成功GetQqMidasPay", res);
                    _handle && _handle({ succ: true, data: res });
                },
                fail: (res) => {
                    console.error("支付失败GetQqMidasPay", res);
                    _handle && _handle({ succ: false, data: res });
                }
            }
        )
    }

}