import ViewBase from "../../engine/ViewBase";
import UIManager from "../../System/ui/UIManager";
import { ViewConfig } from "../../System/ui/UI_Config";
import Timer from "../../Tools/Timer";
import ResourcesManager from "../../engine/ResourceManager";
import { BundleGroupType } from "../../Const/GameConst";
import Tools from "../../Tools/Tools";
import { BasicGameManger } from "../../gamePlaySystem/GameManager/BasicGameManger";
import { GameJsonConfig } from "../../GameJsonConfig";
import BundleMgr from "../BundleMgr";
import GameData from "../GameData";

const { ccclass, property } = cc._decorator;

@ccclass
export default class LoadingView extends ViewBase {

    @property({ type: cc.ProgressBar, displayName: '' })
    progressBar: cc.ProgressBar = null;

    private currentProgress: number = 0; // 当前实际进度
    private targetProgress: number = 0.7; // 目标进度
    private isLoadingComplete: boolean = false; // 是否加载完成

    onLoad() {
        super.onLoad();
        let totalCout = 0;
        let finishCount = 0;
        ResourcesManager.instance.loadBundle(BundleMgr.bundles.setting, (bundle) => {
            totalCout += bundle.getDirWithPath("").length;
            let onProgress = (finish: number, total: number, item: any) => {
                // 实际加载进度，但不会超过 70%
                let actualProgress = finish / total;
                this.targetProgress = Math.min(actualProgress, 0.7);
            };
            let onComplete = () => {
                this.isLoadingComplete = true;
                this.targetProgress = 1; // 设置目标为 100%
            };
            bundle.loadDir("", onProgress, onComplete);
        }, BundleGroupType.Never)
        
        // 启动进度更新循环
        Timer.frameLoop(1, this, this.updateProgress.bind(this));
    }

    showStartView() {

    }

    /**
     * 更新进度的动画效果
     * 第一阶段：快速冲到 70%
     * 第二阶段：慢慢跑到当前实际进度（最多 70%）
     * 第三阶段：加载完成后快速冲到 100%
     */
    private updateProgress() {
        if (this.currentProgress >= this.targetProgress) {
            return; // 已达到目标进度，等待下一步
        }

        let speed: number;
        
        // 第一阶段：快速冲到 70%
        if (this.currentProgress < 0.7 && this.targetProgress <= 0.7) {
            speed = 0.02; // 快速阶段，每帧增加 2%
        }
        // 第二阶段：慢慢跑到当前实际进度（最多 70%）
        else if (!this.isLoadingComplete) {
            speed = 0.003; // 慢速阶段，每帧增加 0.3%
        }
        // 第三阶段：加载完成后快速冲到 100%
        else {
            speed = 0.05; // 完成阶段，每帧增加 5%
        }

        this.currentProgress += speed;
        
        // 确保不超过目标进度
        if (this.currentProgress > this.targetProgress) {
            this.currentProgress = this.targetProgress;
        }
        
        // 确保不超过 100%
        if (this.currentProgress >= 1) {
            this.currentProgress = 1;
        }

        this.progressBar.progress = this.currentProgress;

        // 检查是否完全完成
        if (this.isLoadingComplete && this.currentProgress >= 1) {
            this.OnLoadone();
        }
    }

    public setProgress(progress: number) {
        // 这个方法保留，但现在主要通过 updateProgress 来控制进度
        if (progress < 0) {
            progress = 0;
        } else if (progress >= 1) {
            progress = 1;
        }
        this.targetProgress = progress;
    }

    private OnLoadone() {
        //加载资源到配置 json
        GameJsonConfig.Necessary();
        if(CC_DEBUG && Tools.GetQueryString('lv')){
            GameData.gotoLevel(Tools.GetQueryString('lv'))
        }else{
            UIManager.instance.showView(ViewConfig.HomeView, () => {
                this.closeView(true);
            })
        }
        Timer.clearAll(this);
    }
}

