import BaseStorageValue from "./BaseStorageValue";

/**
 * K是保存的类型
 */
export default class ClassStorageValue<K> extends BaseStorageValue<K> {
    
    protected savefunc : ()=>K;
    protected loadfunc : (value : any)=>void;
    protected obj : any;

    /**
     * 自定义保存
     * @param key key
     * @param value 值
     * @param savefunc 保存方法
     * @param loadfunc 读取方法
     * @param obj 调用类
     */
    public constructor(key : string , value : K , savefunc : ()=>K , loadfunc : (value : any)=>void , obj : any , monitor : boolean = true){
        super(key , value , monitor);
        this.savefunc = savefunc;
        this.loadfunc = loadfunc;
        this.obj = obj;
    }

    Save(_force : boolean = false) : any {
        const _v = this.savefunc.call(this.obj);
        if(_v != this.value || _force){
            this.value = _v;
            return this.value;
        }
        return null
    }
    Load(value: any) : void {
        this.value = value;
        this.loadfunc.call(this.obj , value);
        this.change = true;
    }
    get GetValue() : K{
        return this.value;
    }
    set SetValue(value : K){
        this.value = value;
    }
}