    /**激励广告单例 */
    private videoad: wx.RewardedVideoAd;
    private isready: boolean;
    public ShowRewardedVideoAd(adUnitId: string): Promise<any> {
        if (!this.api) return;
        this.api.showLoading({
            mask: true,
        });
        let _this = this;
        let _r, _j;
        return new Promise(function (resolve, reject) {
            _r = resolve;
            _j = reject;
            _this.videoad = _this.api.createRewardedVideoAd({
                adUnitId: adUnitId
            });
            let waittime;
            let onload = () => {
                _this.isready = true;
                _this.api.hideLoading({ fail() { } });
                if (_this.videoad) {
                    waittime && (clearTimeout(waittime));
                    waittime = null;
                    _this.videoad.show().catch(function (err) {
                        _this.isready = false;
                        delete_videoad();
                    });
                } else {
                    delete_videoad();
                    _j && _j({ errMsg: "广告播放失败" });
                }
            }
            let onerror = (res) => {
                _this.api.hideLoading({ fail() { } });
                _this.isready = false;
                delete_videoad();
                _j && _j(res);
            }
            let onclose = function onclose(res) {
                _this.api.hideLoading({ fail() { } });
                _this.isready = false;
                delete_videoad();
                _r && _r(res);
            };
            let delete_videoad = () => {
                if (_this.videoad) {
                    waittime && (clearTimeout(waittime));
                    waittime = null;
                    _this.videoad.offClose(onclose);
                    _this.videoad.offLoad(onload);
                    _this.videoad.offError(onerror);
                    if (window["tt"] && _this.videoad.destory) {
                        _this.videoad.destory();
                    }
                    _this.videoad = null;
                }
            }
            _this.videoad.onLoad(onload);
            _this.videoad.onError(onerror);
            _this.videoad.onClose(onclose);
            window["tt"] && (_this.videoad.load());
            // _this.videoad.load();
            if (!window["tt"] && window["wx"]) {
                if (_this.videoad.isReady()) {
                    // 微信因为单例不能销毁，要判断是否ready,如果ready，马上就show，不需要等onload回调         
                    _this.api.hideLoading({ fail() { } });
                    waittime && (clearTimeout(waittime));
                    waittime = null;
                    _this.videoad.show().then(function () {
                    }).catch(function (err) {
                        _this.isready = false;
                        delete_videoad();
                    });
                } else {
                    waittime = setTimeout(() => {
                        delete_videoad();
                        _j && _j({ errMsg: "广告播放失败，没有可以播放的广告" });
                    }, 10000);
                }
            } else {
                waittime = setTimeout(() => {
                    delete_videoad();
                    _j && _j({ errMsg: "广告播放失败，没有可以播放的广告" });
                }, 10000);
            }

        });
    }

    private _resolve: any;
    private _reject: any;
    private _loading: boolean;
    private _creating: boolean;
    public QQShowRewardedVideoAd(adUnitId: string): Promise<any> {
        if (!this.api) return;
        this._loading = true;
        let self = this;
        let curPromise = new Promise((resolve, reject) => {
            self._resolve = resolve;
            self._reject = reject;
        })
        // if(!PlatformManager.onPcMiniGame){
        //     this.api.showLoading({
        //         mask: true,
        //     });
        // }
        if (!this.videoad) {
            //创建
            this.videoad = this.api.createRewardedVideoAd({
                adUnitId: adUnitId
            });
            this._creating = true;
            Logger.warn("广告id：", adUnitId)
            this.videoad.onError(this.AdOnError);
            this.videoad.onClose(this.AdOnClose);
            this.videoad.onLoad(this.AdOnLoad);
        } else {
            this.api.createRewardedVideoAd({
                adUnitId: adUnitId
            });
        }

        this.videoad.load().then(() => {
            Logger.log('激励视频加载成功');
            self.videoad.show().then(() => {
                Logger.warn('激励视频 广告显示成功')
            }).catch(err => {
                self._reject && self._reject({ errMsg: "广告播放失败" });
                self.api.hideLoading({
                    fail() {
                        Logger.error("关闭遮挡层失败")
                    }
                });
                Logger.warn('激励视频 广告显示失败')
            })
        }).catch(err => {
            self._reject && self._reject({ errMsg: "广告加载失败" });
            self.api.hideLoading({
                fail() {
                    Logger.error("关闭遮挡层失败")
                }
            });
            Logger.warn('激励视频加载失败');
        });

        return curPromise;
    }

