export default class FguiButton {
   
    protected com : fgui.GComponent;
    protected func : Function;

    constructor(name : string , view : fgui.GComponent , func : Function){
        let c = view.getChild(name);
        this.setClickFunc(func);
        if(c){
            this.com = c.asCom;
            this.com.onClick(this.OnClick , this);
        }        

        return this;
    }

    protected OnClick(evt:fgui.Event){       
        if(!this.com) return;
        this.func();
        CC_DEBUG && window['_TEST_EMIT'] && console.log("OnClick", this.func);
    }

    public setClickFunc(func : Function){
        this.func = func;
    }

    set touchable(_value : boolean){
        if(!this.com) return;
        this.com.touchable = _value;
    }

    get touchable(){
        if(!this.com) return false;
        return this.com.touchable;
    }

    set visible(_value : boolean){
        if(!this.com) return;
        this.com.visible = _value;
    }

    get visible(){
        if(!this.com) return false;
        return this.com.visible;
    }

    set x(_v : number){
        if(!this.com) return;
        this.com.x = _v;
    }

    get x(){
        if(!this.com) return 0;
        return this.com.x;
    }

    set y(_v : number){
        if(!this.com) return;
        this.com.y = _v;
    }

    get y(){
        if(!this.com) return 0;
        return this.com.y;
    }

    set width(_v : number){
        if(!this.com) return;
        this.com.width = _v;
    }

    get width(){
        if(!this.com) return 0;
        return this.com.width;
    }

    set height(_v : number){
        if(!this.com) return;
        this.com.height = _v;
    }

    get height(){
        if(!this.com) return 0;
        return this.com.height;
    }

    set grayed(_v : boolean){
        if(!this.com) return;
        this.com.grayed = _v;
    }

    get grayed(){
        if(!this.com) return false;
        return this.com.grayed;
    }

    get node(){
        if(!this.com) return null;
        return this.com.node;
    }

    localToGlobal(ax? : number ,  ay? : number , result? : cc.Vec2){
        if(!this.com) return;
        return this.com.localToGlobal(ax , ay , result);
    }

    globalToLocal(ax? : number ,  ay? : number , result? : cc.Vec2){
        if(!this.com) return;
        this.com.globalToLocal(ax , ay , result);
    }

    getChild(_name : string) {
        if(!this.com) return null;
        return this.com.getChild(_name);
    }

    getController(_n : string){
        if(!this.com) return null;
        return this.com.getController(_n);
    }

    Dispose(){
        if(!this.com) return;
        this.com.offClick(this.OnClick , this);
    }
}