
export default class CheckOnTransparent {

    static pixelsDataMap: Map<string, Uint8Array> = new Map();
    static clear() {
        // this.pixelsDataMap.forEach((value, key) => {
        //     value.length
        // });
        this.pixelsDataMap.clear();
    }   

    /**
     * 
     * @param point 
     * @param nodeTarget 
     * @returns true 非透明区域，false透明区域
     */
    static hitCheck(event:  cc.Event.EventTouch, nodeTarget: cc.Node) {
        // 点击位置
        const touchPos = event.getLocation(),
            localPos = nodeTarget.convertToNodeSpaceAR(touchPos);

        let sprite = nodeTarget.getComponent(cc.Sprite);
        if (sprite) {
            let pixelsData: Uint8Array;
            // 获取像素数据
            if (!this.pixelsDataMap.has(nodeTarget.uuid)) {
                pixelsData = this.getPixelsData(nodeTarget);
                this.pixelsDataMap.set(nodeTarget.uuid, pixelsData);
            } else {
                pixelsData = this.pixelsDataMap.get(nodeTarget.uuid);
            }

            // 截取像素颜色
            let x = localPos.x + nodeTarget.anchorX * nodeTarget.width,
                y = -(localPos.y - nodeTarget.anchorY * nodeTarget.height);
            const index = (nodeTarget.width * 4 * Math.floor(y)) + (4 * Math.floor(x)),
                colors = pixelsData.slice(index, index + 4);

            if(colors[3]){
                return true;
            }else{
                return false;
            }
        }
        console.error("透明区域处理失败");
        return false;
    }

    // 判断
    static isTransparency(img, x, y) {
        var cvs = document.createElement("canvas");
        var ctx = cvs.getContext('2d');
        cvs.width = 1;
        cvs.height = 1;
        ctx.drawImage(img, x, y, 1, 1, 0, 0, 1, 1);
        var imgdata = ctx.getImageData(0, 0, 1, 1);
        return imgdata.data[3]; // 第三个分量来判断，webgl常用来判断点击的手法
    }


    /**
   * 获取像素数据
   * @param node 节点
   * @param flipY 垂直翻转数据
   */
    public static getPixelsData(node: cc.Node, flipY: boolean = true): Uint8Array {
        if (!cc.isValid(node)) {
            return null;
        }
        // 节点宽高
        const width = Math.floor(node.width),
            height = Math.floor(node.height);
        // 创建临时摄像机用于渲染目标节点
        const cameraNode = new cc.Node();
        cameraNode.parent = node;
        const camera = cameraNode.addComponent(cc.Camera);
        camera.clearFlags |= cc.Camera.ClearFlags.COLOR;
        camera.backgroundColor = cc.color(0, 0, 0, 0);
        camera.zoomRatio = cc.winSize.height / height;
        // 将节点渲染到 RenderTexture 中
        const renderTexture = new cc.RenderTexture();
        renderTexture.initWithSize(width, height, cc.RenderTexture.DepthStencilFormat.RB_FMT_S8);
        camera.targetTexture = renderTexture;
        camera.render(node);
        // 获取像素数据
        const pixelsData = renderTexture.readPixels();
        // 销毁临时对象并返回数据
        renderTexture.destroy();
        cameraNode.destroy();
        // 垂直翻转数据
        if (flipY) {
            const length = pixelsData.length,
                lineWidth = width * 4,
                data = new Uint8Array(length);
            for (let i = 0, j = length - lineWidth; i < length; i += lineWidth, j -= lineWidth) {
                for (let k = 0; k < lineWidth; k++) {
                    data[i + k] = pixelsData[j + k];
                }
            }
            return data;
        }
        return pixelsData;
    }
}
