import { Logger } from "../../engine/Logger";
import ResourcesManager from "../../engine/ResourceManager";
import NumberStorageValue from "../Storage/NumberStorageValue";
import StorageSystem from "../Storage/StorageSystem";
import BaseGameSystem from "../BaseGameSystem";

export class SoundManager extends BaseGameSystem {

    ClearData() {
        this.StopBgm();
    }

    static max_playsound_count: number = 1;
    static last_music_path: cc.AudioClip;
    private _music: NumberStorageValue;// = 1;
    get music() { return this._music.GetValue }
    private _sound: NumberStorageValue;// = 1;
    get sound() { return this._sound.GetValue }

    protected cur_bgm_url : string;
    protected cur_bgm_bundle : string;

    constructor() {
        super();
        this._music = new NumberStorageValue("SettingMusic", 1);
        this._sound = new NumberStorageValue("SettingSound", 1);
        this.cur_bgm_url = null;
        // cc.audioEngine.setMaxAudioInstance(10);
        cc.audioEngine.setMusicVolume(this._music.GetValue * 0.5);
    }
    /** 音乐 */
    ChangeMusic(on: boolean = null) {
        if (on == null) {
            this._music.SetValue = (this._music.GetValue + 1) % 2;
        } else {
            this._music.SetValue = on ? 1 : 0;
        }
        StorageSystem.Init.Save();
        cc.audioEngine.setMusicVolume(this._music.GetValue * 0.5);
        
        if(this._music.GetValue == 1 && this.cur_bgm_bundle && this.cur_bgm_url){
            ResourcesManager.instance.loadBundle(this.cur_bgm_bundle , (bundleObj) => {
                bundleObj.load(this.cur_bgm_url, cc.AudioClip, null, (err, clip) => {               
                    cc.audioEngine.playMusic(clip, true);
                });
            });
        }
    }
    PlayBgm(bundle: string, url: string) {       
        if(this.cur_bgm_url == url) return;
        this.cur_bgm_bundle = bundle;
        this.cur_bgm_url = url;     //记录当前播放的数据
        if(this._music.GetValue == 0) return;
        ResourcesManager.instance.loadBundle(bundle, (bundleObj) => {
            bundleObj.load(url, cc.AudioClip, null, (err, clip) => {               
                cc.audioEngine.playMusic(clip, true);
            });
        });
    }
    StopBgm() {
        this.cur_bgm_url = null;
        this.cur_bgm_bundle = null;
        SoundManager.last_music_path = null;
        cc.audioEngine.stopMusic();
    }
    /** 音效 */
    ChangeSound(on: boolean = null) {
        if (on == null) {
            this._sound.SetValue = (this._sound.GetValue + 1) % 2;
        } else {
            this._sound.SetValue = on ? 1 : 0;
        }
        StorageSystem.Init.Save();
        cc.audioEngine.setEffectsVolume(this._sound.GetValue);
    }
    PlaySound(bundle: string, url: string) {
        if (this._sound.GetValue == 0) { return; }
        ResourcesManager.instance.loadBundle(bundle, (bundleObj) => {
            bundleObj.load(url, cc.AudioClip, null, (err, clip) => {               
                clip ? cc.audioEngine.playEffect(clip, false) : console.error("SoundManager.PlaySound: 播放失败, 音效文件不存在:", url);
            });
        });        
    }

    Wx_OnShow(){
        if(this._music.GetValue == 1 && this.cur_bgm_bundle && this.cur_bgm_url){
            let _url = this.cur_bgm_url;
            let _bundle = this.cur_bgm_bundle;
            this.StopBgm();
            ResourcesManager.instance.loadBundle(_bundle , (bundleObj) => {
                bundleObj.load(_url , cc.AudioClip, null, (err, clip) => {               
                    cc.audioEngine.playMusic(clip, true);
                });
            });
        }
    }

    Wx_OnHide(){
        
    }
}
const SoundSystem = new SoundManager();
export default SoundSystem;