import Singleton from "../../singleton/Singleton";
import BaseGameSystem from "../BaseGameSystem";
import { GameEvent } from "../GameEvent/GameEvent";
import { IUser } from "./UserAttribute";

export class UserManager extends BaseGameSystem {
    ClearData() {
        this.data = {
            money: 0,
            coupon: 0,
            diamond: 0,
            guildCoin: 0,
        }
    }

    private data: IUser;
    get Money(): number { return this.data.money; }
    set Money(value: number) {
        if (this.data.money == value) { return; }
        this.data.money = value;
        Singleton.GameEventSystem.event(GameEvent.MONEY_CHANGE, this.data.money);
    }
    get Coupon(): number { return this.data.coupon; }
    set Coupon(value: number) {
        this.data.coupon = value;
        Singleton.GameEventSystem.event(GameEvent.COUPON_CHANGE, this.data.coupon);
    }
    get Diamond(): number { return this.data.diamond; }
    set Diamond(value: number) {
        this.data.diamond = value;
        Singleton.GameEventSystem.event(GameEvent.DIAMOND_CHANGE, this.data.diamond);
    }

    get GuildCoinCount() {
        return this.data.guildCoin;
    }
    set GuildCoinCount(value: number) {
        this.data.guildCoin = value;
        Singleton.GameEventSystem.dispatch(GameEvent.GuildCoinChange);
    }


    private update_time: number = -1;

    /** 获取账号数据 */
    GetGameData() { }

    /** 选择人物时带的数据 */
    SetDataFormChooseActor(res) {
        this.Money = res.gold;
        this.Coupon = res.coupon;
        this.Diamond = res.diamond;
        this.GuildCoinCount = res.guild_coin;
    }

    AddMoney(value: number) {
        // GamePostManager.Gold({ amount: value, type: 1 }).then(res => {
        //     this.Money = res.data.gold;
        //     Debug.log(0 , "增加金钱成功，现在金钱", this.data.money);
        // });
    }
    AddCoupon(value: number) {
        // GamePostManager.Coupon({ amount: value, type: 1 }).then(res => {
        //     this.Coupon = res.data.coupon;
        //     Debug.log(0 , "增加点券成功，现在点券", this.data.coupon);
        // });
    }

}
const UserSystem = new UserManager();
export default UserSystem;