const {ccclass, property} = cc._decorator;

@ccclass
export default class NewClass extends cc.Component {

    @property(cc.Vec2)
    offset: cc.Vec2 = new cc.Vec2(1,1);

    @property(cc.Vec2)
    tilingoffset: cc.Vec2 = new cc.Vec2(0,0);

    @property
    row_count : number = 1;

    @property
    max_count : number = 1;

    @property
    speed : number = 1;

    // LIFE-CYCLE CALLBACKS:

    protected mat : cc.MaterialVariant;
    protected time : number;
    protected index : number;

    onLoad () {
        this.mat = this.getComponent(cc.Sprite).getMaterials()[0];
        this.time = 0;
        this.index = 0;
    }

    start () {

    }

    update (dt) {
        this.time += dt;
        if(this.time >= this.speed){
            let _tx = (this.index % this.row_count) * this.offset.x;
            let _ty = Math.floor(this.index / this.row_count) * this.offset.y;
            this.mat.setProperty("myUV" , [this.offset.x , this.offset.y]);
            this.mat.setProperty("tilingOffset" , [_tx , _ty]);
            this.time = 0;
            this.index = (this.index+1)%this.max_count;
        }
    }
}
