import ViewBase from "../../engine/ViewBase";

const {ccclass, property} = cc._decorator;

@ccclass
export default class TiktokView extends ViewBase {

	@property({ type: cc.Node, displayName:'' })
	openUrlBtn: cc.Node = null;

	@property({ type: cc.Node, displayName:'' })
	closeBtn: cc.Node = null;


    start () {
		
		this.onAddEvent(this.closeBtn,()=>{
			this.closeView();
		})


		this.onAddEvent(this.openUrlBtn, () => {
			this.closeView();
		})

    }

	onDisable(): void {
	}
	
	onInitChild(level: number){
	}

}
