import HttpRequest, { HTTP_COMPLETE, HTTP_ERROR } from "./HttpUtil";
import { Logger } from "../Logger";

/*
 * @Author: your name
 * @Date: 2022-01-15 18:06:39
 * @LastEditTime: 2022-12-08 12:19:30
 * @LastEditors: 卢小雨
 * @Description: 打开koroFileHeader查看配置 进行设置: https://github.com/OBKoro1/koro1FileHeader/wiki/%E9%85%8D%E7%BD%AE
 * @FilePath: \GameClient\assets\src\System\HttpRequest\HttpRequestManager.ts
 */
export default class HttpRequestManager {

    static Post(url, data = null, headers: string[] = null, complete_handle?: Function , error_handle?: Function , progress_handle?: Function): Promise<any> {
        return new Promise((resolve, reject) => {     
            let xhr: HttpRequest = new HttpRequest();
            xhr.methodType = "POST";
            xhr.timeOut = CC_JSB ? 120000 : 5000;  //设置超时时间
            xhr.tryCount = 10;
            xhr.once(HTTP_COMPLETE , (res) => {
                if (complete_handle) {
                    complete_handle();
                }
                Logger.log(0 , res);
                resolve(res);
            } , this);
            xhr.once(HTTP_ERROR, (error) => {
                if (error_handle) {
                    error_handle();
                }
                Logger.log(0 , error);
                reject(error);
            },this);            
            if (headers != null) {
                for (var i = 0; i < headers.length; i+=2) {
                    xhr.setRequestHeader(headers[i] , headers[i+1]);
                }
            }
            let str = "";
            if (data != null) {
                // const keys = Object.keys(data);
                // for (let _k in keys) {
                //     str += keys[_k] + "=" + data[keys[_k]] + "&";
                // }
                for (let key in data) {
                    if (typeof (data[key]) == "object") {
                        str += key + "=" + encodeURIComponent( JSON.stringify(data[key]) ) + "&";
                    } else {
                        str += key + "=" + encodeURIComponent( data[key] ) + "&";
                    }
                }
                str = str.substring(0, str.length - 1);
                Logger.log(0 , str);
            }
            Logger.log(0 , "send", url, str);
            xhr.send(url, str);
        });
    }

    static Get(url, data = null, complete_handle?: Function , error_handle?: Function , progress_handle?: Function): Promise<any> {
        return new Promise((resolve, reject) => {     
            let xhr: HttpRequest = new HttpRequest();
            xhr.methodType = "GET";
            xhr.timeOut = 120000;  //设置超时时间
            xhr.tryCount = 10;
            xhr.once(HTTP_COMPLETE , (res) => {
                if (complete_handle) {
                    complete_handle();
                }
                // Debug.log(0 , res);
                resolve(res);
            } , this);
            xhr.once(HTTP_ERROR, (error) => {
                if (error_handle) {
                    error_handle();
                }
                // Debug.log(0 , error);
                reject(error);
            },this);            
            let str = "";
            if (data != null) {
                // const keys = Object.keys(data);
                // for (let _k in keys) {
                //     str += keys[_k] + "=" + data[keys[_k]] + "&";
                // }
                for (let key in data) {
                    if (typeof (data[key]) == "object") {
                        str += key + "=" + encodeURIComponent(JSON.stringify(data[key])) + "&";
                    } else {
                        str += key + "=" + encodeURIComponent(data[key]) + "&";
                    }
                }
                str = str.substring(0, str.length - 1);
                // Debug.log(0 , str);
            }
            Logger.warn(0 , "send", url, str);
            xhr.send(url, str);
        });
    }
}

CC_DEBUG && (window['HttpRequestManager'] = HttpRequestManager);