    private static readonly NumberUnitStr: string[] = ["", "K", "M", "B", "EE", "P", "T", "X", "Z", "KZ", "MZ", "BZ", "EZ", "PZ", "TZ", "XZ", "ZZ"];
    /** 字符 */
    static NumberUnit(num: number): string {
        if (num < 1000000) {
            return num + "";
        }
        let unitCount = 0;
        while (num > 1000) {
            num = num / 1000;
            unitCount++;
        }
        if (unitCount >= Tools.NumberUnitStr.length) {
            unitCount = Tools.NumberUnitStr.length - 1
        }
        return num.toFixed(2) + Tools.NumberUnitStr[unitCount];
        //return num.toFixed(Math.min((num%1+"").length,2))+GameFormula.NumberUnitStr[unitCount];//小数点后4位+单位
    }

    /** 随机长度字符串 */
    public static RandomString(_len: number) {
        _len = _len || 32;
        var t = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz123456789",
            a = t.length,
            n = "";
        for (let i = 0; i < _len; i++) n += t.charAt(Math.floor(Math.random() * a));
        return n
    }


