    private static _queryBuf = {};
    static GetQueryString(name): any {
        if (this._queryBuf.hasOwnProperty(name)) {
            return this._queryBuf[name];
        }
        var reg = new RegExp("(^|&)" + name + "=([^&]*)(&|$)");
        var r = window.location.search ? window.location.search.substr(1).match(reg) : null;
        if (r != null){
            return this._queryBuf[name] = r[2];     //注意这里不能用js里面的unescape方法
        }
        return this._queryBuf[name] = null;
    }


    static webCopyString(str: string): boolean {
        let input: string = str;
        const el: any = window.document.createElement('textarea');
        el.value = input;
        el.setAttribute('readonly', '');
        el.style.contain = 'strict';
        el.style.position = 'absolute';
        el.style.left = '-9999px';
        el.style.fontSize = '12pt'; // Prevent zooming on iOS
        const selection: any = window.getSelection();
        let originalRange: any = false;
        if (selection.rangeCount > 0) {
            originalRange = selection.getRangeAt(0);
        }
        window.document.body.appendChild(el);
        el.select();
        el.selectionStart = 0;
        el.selectionEnd = input.length;
        let success: boolean = false;
        try {
            success = window.document.execCommand('copy');
        } catch (err) {

        }
        window.document.body.removeChild(el);
        if (originalRange) {
            selection.removeAllRanges();
            selection.addRange(originalRange);
        }
        return success;
    }


    static StrToNumArray(str: string, splitter: string): number[] {
        if (str == null) { return []; }
        if (str == "") { return []; }
        let s = str.split(splitter);
        let n = [];
        for (var i = 0, len = s.length; i < len; i++) {
            n.push(+s[i]);
        }
        return n;
    }

