    static CopyObject<T>(_obj: T): T {
        if (_obj == null) return null;
        let _data = Array.isArray(_obj) ? [] : {};
        const _keys = Object.keys(_obj);
        _keys.forEach((value) => {
            if (typeof (_obj[value]) == "object") {
                _data[value] = Tools.CopyObject(_obj[value]);
            } else
                _data[value] = _obj[value]
        });
        return _data as T;
    }

    static downloadFile(data, name) {
        let ele_a = window.document.createElement("a");
        let fileName = name + ".json";
        ele_a.download = fileName;
        ele_a.style.display = 'none';
        let blob = new Blob([JSON.stringify(data)]);
        ele_a.href = URL.createObjectURL(blob);
        window.document.body.appendChild(ele_a);
        ele_a.click();
        document.body.removeChild(ele_a);
    }

    static delayCallback(dt: number, node: cc.Node, callback: Function) {
        return cc.tween(node).delay(dt).call(callback).start();
    }

    static uniqArr(arr): any[] {
        var newArr = new Set(arr)
        return Array.from(newArr)
    }

    static stringChatCodeAdd(_str : string) : number{
        let _r = 0;
        for(let i = 0 , len = _str.length ; i < len ; i++){
            _r += _str.charCodeAt(i);
        }
        return _r;
    }

    /**
     * cocos富文本不支持的格式在这里做些转换
     * @param text 
     * @returns 
     */
    static FormatRichText(text: string){
        let _r = text;
        _r = _r.replace(/<\/p>/g, "<\/p>\n");
        _r = _r.replace(/&nbsp;/g, "&nbsp; ");

        return _r;
    }
