import BasePlatformAPI from "./BasePlatformAPI";

export class GameControllerApi extends BasePlatformAPI {

    private static _controller: GameControllerApi = null;
    public static get instance(): GameControllerApi {
        if (this._controller == null) {
            this._controller = new GameControllerApi();
        }
        return this._controller;
    }

    //退出游戏
    public OutGame() {
        this.api.exitMiniProgram();
    }
}