import ViewBase from "../../engine/ViewBase";
import { GameViewEvent, HintConfig, LevelConfig } from "../../gamePlaySystem/GameAttribute";
import { BasicGameManger } from "../../gamePlaySystem/GameManager/BasicGameManger";
import { HintInfo } from "../../gamePlaySystem/LogicBlock/BaseLogicBlock";
import Singleton from "../../singleton/Singleton";
import { ViewConfig } from "../../System/ui/UI_Config";
import UIManager from "../../System/ui/UIManager";
import VideoAdSystem from "../../System/VideoAd/VideoAdManager";
import Timer from "../../Tools/Timer";
import SceneAPI from "../../wx_api/SceneAPI";
import GameData from "../GameData";

const {ccclass, property} = cc._decorator;

@ccclass
export default class GameNdrgView extends ViewBase {

	@property({ type: cc.Node, displayName:'' })
	rightBtn: cc.Node = null;

	@property({ type: cc.Node, displayName:'' })
	leftBtn: cc.Node = null;

	@property({ type: cc.Node, displayName:'' })
	addCountBtn: cc.Node = null;
	@property({ type: cc.Label, displayName:'' })
	errCountLab: cc.Label = null;

	@property({ type: cc.Node, displayName:'' })
	tipIco: cc.Node = null;

	@property({ type: cc.Node, displayName:'' })
	errIco: cc.Node = null;

	@property({ type: cc.Node, displayName:'' })
	correctIco: cc.Node = null;

	@property({ type: cc.ParticleSystem, displayName:'' })
	clickEff: cc.ParticleSystem = null;

	@property({ type: cc.Sprite, displayName:'' })
	progressBarBg: cc.Sprite = null;

	@property({ type: cc.Sprite, displayName:'' })
	progressBar: cc.Sprite = null;

	@property({ type: cc.Sprite, displayName:'' })
	timeFilled: cc.Sprite = null;

	@property({ type: cc.Sprite, displayName:'' })
	hintEff: cc.Sprite = null;

	@property({ type: cc.Prefab, displayName:'' })
	settlementView: cc.Prefab = null;

	@property({ type: cc.Prefab, displayName:'' })
	gameMenuPanel: cc.Prefab = null;

	@property({ type: cc.Prefab, displayName:'' })
	gameTimeoutPanel: cc.Prefab = null;

	@property({ type: cc.Sprite, displayName:'' })
	menuBtn: cc.Sprite = null;

	@property({ type: cc.Node, displayName:'' })
	addTimeBtn: cc.Node = null;

	@property({ type: cc.Sprite, displayName:'' })
	replayBtn: cc.Sprite = null;

	@property({ type: cc.Layout, displayName:'' })
	mainLayout: cc.Layout = null;
	
	@property({ type: cc.Sprite, displayName:'' })
	hintHand: cc.Sprite = null;

	@property({ type: cc.Sprite, displayName:'' })
	hintImg: cc.Sprite = null;

	@property({ type: cc.Node, displayName:'' })
	hintPanel: cc.Node = null;

	@property({ type: cc.Sprite, displayName:'' })
	hintBtn: cc.Sprite = null;

	@property({ type: cc.Node, displayName:'' })
	closeBtn: cc.Node = null;

	@property({ type: cc.Sprite, displayName:'' })
	lvScrollview: cc.Sprite = null;

	@property({ type: cc.Node, displayName:'' })
	goodsScrollview: cc.Node = null;

	@property({ type: cc.Node, displayName:'' })
	goodsRootNode: cc.Node = null;

	@property({ type: cc.Node, displayName:'' })
	goodsItem: cc.Node = null;

	@property({ type: cc.Node, displayName:'' })
	content: cc.Node = null;

	@property({ type: cc.Label, displayName:'' })
	countLabel: cc.Label = null;

	@property({ type: cc.Label, displayName:'' })
	timeoutLabel: cc.Label = null;

	@property({ type: cc.Label, displayName:'' })
	titleLabel: cc.Label = null;
	hintCfg: HintConfig;

	set Title(v: string){
		this.titleLabel.string = v;
	}
	

	currGoodsIdx: number;

	onLoad(){

		// this.onAddEvent(this.closeBtn,()=>{
		// 	GameData.CurGM.onDestory();
		// });

		this.onAddEvent(this.hintPanel,()=>{
			this.hintPanel.active = false;
		});

		// 加时间
		this.onAddEvent(this.addTimeBtn,()=>{
			GameData.CurGM.addTime(60);
		});

		this.onAddEvent(this.addCountBtn,()=>{
			GameData.CurGM.addErrCount(3);
		});

		this.onAddEvent(this.rightBtn,()=>{
			GameData.CurGM.onViewEvent(GameViewEvent.RightPage);
		});

		this.onAddEvent(this.leftBtn,()=>{
			GameData.CurGM.onViewEvent(GameViewEvent.LeftPage);
		});



		// 重新玩
		this.onAddEvent(this.replayBtn.node,()=>{
			GameData.gotoLevel(GameData.CurGM.Level);
		});

		this.onAddEvent(this.menuBtn.node, ()=>{
            UIManager.instance.showView(ViewConfig.GameMenuPanel,()=>{})
		})

		// 屏幕点击效果
		this.lvScrollview.node.on(cc.Node.EventType.TOUCH_START,(event: cc.Event.EventTouch)=>{
			this.clickEff.resetSystem();
			this.clickEff.node.setPosition(this.clickEff.node.parent.convertToNodeSpaceAR( event.getLocation()));
			Singleton.SoundSystem.PlaySound("resources", "sound/click")
		})

		this.onAddEvent(this.hintBtn.node, this.hintEvent.bind(this))
	}

	setTimeout(v: string, pro: number){
		this.timeoutLabel.string = v;
		this.timeFilled.fillRange = pro;
	}

	/**
	 * 
	 * @param headName  "进度:"
	 * @param numberFrame "${count}/10"
	 * @returns 
	 */
	setProgress(headName: string, count: number, max_count: number){
		if(!headName){
			this.progressBarBg.node.active = false;
			return;
		}
		count = (count || 0);
		this.progressBarBg.node.active = true;
		this.progressBar.fillRange = count/max_count;
		this.countLabel.string = headName + ` ${count}/${max_count}`;
	}

	onInitChild(level: string){
		Singleton.SoundSystem.PlayBgm("resources", "sound/game_bgm");
		this.content.destroyAllChildren();
		this.goodsScrollview.active = false;
		this.currGoodsIdx = 0;
	}

	setGoodsCount(count: number){
		if(!count) return;
		this.goodsScrollview.active = true;
		for (let i = 0; i < count; i++) {
			this.createGoodsItem();
		}
	}
	
    setErrCount(count: any) {
        this.errCountLab.string = count+"";
    }

	createGoodsItem(){
		let itemNode = cc.instantiate(this.goodsItem);
		itemNode.active = true;
		itemNode.parent = this.goodsRootNode;
		itemNode.y = 0;
		itemNode.getComponentInChildren(cc.Label).string = ''
		cc.find('bg/goolds',itemNode).active = false;
		return itemNode;
	}
	
	setGoodsItem(name: string, img: cc.SpriteFrame){
		let itemNode = this.goodsRootNode.children[this.currGoodsIdx];
		this.currGoodsIdx ++;
		if(!itemNode){
			itemNode = this.createGoodsItem();
		}
		
		itemNode.getComponentInChildren(cc.Label).string = name;
		let sprite = cc.find('bg/goolds', itemNode).getComponent(cc.Sprite);
		sprite.spriteFrame = img;
		itemNode.active = true;
		sprite.node.active = true;
	}

	addLvContent(node: cc.Node){
		this.content.addChild(node);
		this.content.width = cc.winSize.width;
		this.content.height = cc.winSize.height;
		node.x = node.y = 0;
		// this.lvScrollview.node.height = this.content.height < 1500 ? this.content.height : 1500;
	}
	
	setHintDate(hint: HintConfig) {
		this.hintCfg = hint;
	}

    playErrEffect(pos: cc.Vec2) {
		this.errIco.setPosition(this.errIco.parent.convertToNodeSpaceAR(pos));
		this.errIco.active = true;
		// 播放动效: 从大缩小淡入, 停留1秒, 消失
		// 播放动效: 从大缩小淡入, 停留1秒, 反向播放消失
		this.errIco.scale = 1.2;
		this.errIco.opacity = 0;
		this.errIco.stopAllActions();
		cc.tween(this.errIco)
			.to(0.2, { scale: 1, opacity: 255 })
			.delay(0.25)
			.to(0.2, { scale: 1.2, opacity: 0 })
			.call(() => {
				this.errIco.active = false;
			}).union().start();
    }

	
	/** 提示内容 */
	async hintEvent(){

		// type 提示类型, 0 默认提示、1图片、2圈起来
		if(!this.hintCfg || !this.hintCfg.type){
			let hintInfo = GameData.CurGM.getHintInfo();
			if(!hintInfo){
				console.warn("没有配置提示信息", this.hintCfg);
				SceneAPI.Init.ShowToast("您已选错步骤, 无法通关了, 请重新开始", 'none', 5);
				return;
			}
			let scucess = await VideoAdSystem.PlayerVideoAd();
			if(!scucess || !this.isValid) return;
			this.showHintHand(hintInfo);
			return console.warn("没有配置提示信息", this.hintCfg);
		}
		
		let scucess = await VideoAdSystem.PlayerVideoAd();
		if(!scucess || !this.isValid) return;
		
		this.hintPanel.active = true;
		if(this.hintCfg.type == 1){
			let spr = cc.assetManager.getBundle(GameData.CurGM.BundleName).get('img/'+this.hintCfg.img, cc.SpriteFrame);
			if(!spr) console.error('提示图片不存在', this.hintCfg)
			this.hintImg.spriteFrame = spr;
		}else if(this.hintCfg.type == 2){
			
		}
	}

	showHintHand(hintInfo: HintInfo){
		if(!hintInfo){
			return console.error("没有默认提示信息", hintInfo);
		}

		let handEff = (repeat: number = 0)=>{
			this.hintEff.node.active = true;
			this.hintEff.node.stopAllActions();
			let act = cc.tween(this.hintEff.node).set({opacity: 255,scale:0.5}).to(repeat ? 0.5 : 0.25, {opacity: 0,scale: 2});
			if(repeat){
				act = act.repeat(repeat)
			}
			act.union().start();
		}

		this.hintHand.node.active = true;
		this.hintHand.node.stopAllActions();
		if(hintInfo.pos.length == 1){
			this.hintHand.node.setPosition(hintInfo.pos[0]);
			handEff(hintInfo.type == "click_dobule" ? 1 : 0);
			cc.tween(this.hintHand.node).delay(3).call(()=>{
				this.hintHand.node.active = false;
			}).start()
		}else{
			// 播放动作
			this.hintHand.node.setPosition(hintInfo.pos[0]);
			let act = cc.tween(this.hintHand.node).set({x: hintInfo.pos[0].x, y: hintInfo.pos[0].y}).call(()=>handEff()).delay(0.5);
			for (let i = 1; i < hintInfo.pos.length; i++) {
				act = act.to(0.5, {x: hintInfo.pos[i].x, y: hintInfo.pos[i].y}).call(()=>handEff()).delay(0.8);
			}
			act.union().repeat(3).delay(2).call(()=>{
				this.hintHand.node.active = false;
			}).start()
		}
	}

	onDestroy(){
		Timer.clearAll(this);
		console.log("GameView onDestroy")
	}
}
