import Singleton from "../../game/singleton/Singleton";
import BaseStorageValue from "./BaseStorageValue";
import StorageSystem from "./StorageSystem";

/**
 * 布尔值类型保存
 */
export default class BoolStorageValue extends BaseStorageValue<boolean> {

    public constructor(key : string , value : boolean , monitor : boolean = true){
        super(key , value , monitor);
    }

    Save(_force : boolean = false) : any {
        if(this.change || _force){
            this.change = false;
            return this.value ? 1 : -1;
        }else{
            return null;
        }
    }
    Load(value: any) {
        if(value == undefined || value == null || value == "") return;
        this.value = Number(value) == 1;
        this.change = true;
    }
    get GetValue(){ return this.value;}
    set SetValue(value : boolean){ this.value = value; this.change = true;}
}