import GameEventSystem from "../System/GameEvent/GameEvent";
import SettingSystem from "../System/Setting/SettingManager";
import SoundSystem from "../System/Sound/SoundManager";
import UserSystem from "../System/User/UserManager";
import VideoAdSystem from "../System/VideoAd/VideoAdManager";
import Singleton from "./Singleton";

export default class InitSingleton {
    static Init() {
        Singleton.UserSystem = UserSystem;
        Singleton.VideoAdSystem = VideoAdSystem;
        Singleton.SettingSystem = SettingSystem;
        Singleton.SoundSystem = SoundSystem;
        Singleton.GameEventSystem = GameEventSystem;

        if (CC_DEBUG) {
            window["Singleton"] = Singleton;
        }
    }

}