export default class PlatformManager {

    public static get PlatformName() : string {
        if(this.onWeiXin){
            return "wechat";
        }
        if(this.onTTMiniGame){
            return "zijie";
        }
    }

    public static get onWeiXin(): boolean {
        return cc.sys.platform == cc.sys.WECHAT_GAME;
    }

    public static get onTTMiniGame(): boolean {
        // return Laya.Browser.window["tt"] != null || Laya.Browser.onTTMiniGame;
        return cc.sys.platform == cc.sys.BYTEDANCE_GAME;
    }

    public static get onQQMiniGame(): boolean {
        if(CC_DEBUG && Tools.GetQueryString("miniGame") == '1'){
            return true;
        }
        return cc.sys.platform == cc.sys.QQ_PLAY;
    }

    public static get onPcMiniGame(): boolean {
        if(CC_DEBUG && Tools.GetQueryString("miniGame") == '1'){
            return false;
        }
        return cc.sys.os == cc.sys.OS_WINDOWS ||
        cc.sys.os == cc.sys.OS_OSX || cc.sys.os == null;
    }

    public static get InPlatform(): boolean {
        return cc.sys.platform == cc.sys.QQ_PLAY || cc.sys.platform == cc.sys.BYTEDANCE_GAME || cc.sys.platform == cc.sys.WECHAT_GAME;
    }

    public static get GetAdpter(): IAdpter {
        // if (this.onWeiXin) {
        //     return Laya.MiniAdpter;
        // }
        // if (this.onTTMiniGame) {
        //     return Laya.TTMiniAdapter;
        // }
        return null;
    }

    public static get Is_IOS(): boolean {
        if(CC_JSB){
            return cc.sys.os == "iOS";
        }else{
            if (this.onWeiXin) {
                return cc.sys.os == "iOS";
            }
            if (this.onTTMiniGame) {
                return cc.sys.os == "iOS";
            }
            if(this.onQQMiniGame){
                return cc.sys.os ==  "iOS";
            }
            return false;
        }
    }

    public static get Is_Android(): boolean {
        if(CC_JSB){
            return cc.sys.os == "Android";
        }else{
            if (this.onWeiXin) {
                return cc.sys.os ==  "Android";
            }
            if (this.onTTMiniGame) {
                return cc.sys.os ==  "Android";
            }
            if(this.onQQMiniGame){
                return cc.sys.os ==  "Android";
            }
            return false;
        }        
    }
}