import BaseStorageValue from "./BaseStorageValue";
import StorageSystem from "./StorageSystem";

/**
 * 布尔值类型保存
 * 可随时存储
 * 实例化的时候取本地数据
 */
export default class BoolStorageValue1 extends BaseStorageValue<boolean> {

    /**
     * 
     * @param key 
     * @param value 默认值 
     * @param monitor 
     */
    public constructor(key: string, value: boolean, monitor: boolean = true) {
        super(key, value, monitor);
        this.Load(StorageSystem.Init.LoadToLocal(this.key));
    }

    Save(_force: boolean = false): any {
        if (this.change || _force) {
            this.change = false;
            return this.value ? 1 : -1;
        } else {
            return null;
        }
    }
    SyncSave(){
        if(this.change = true){
            let result = this.Save();
            StorageSystem.Init.SaveToLocal(this.key, result);
        }
    }
    Load(value: any) {
        if (value == undefined || value == null || value == "") return;
        this.value = Number(value) == 1;
        this.change = true;
    }
    get GetValue() { return this.value; }
    set SetValue(value: boolean) { this.value = value; this.change = true; }
    set SetValueAndSaveSelf(vale: boolean) {
        let old = this.value;
        this.value = vale;
        this.change = true;
        let result = this.Save();
        if(old != this.value) StorageSystem.Init.SaveToLocal(this.key, result);
    }
}