import PlatformManager from "../System/Platform/PlatformManager";
import { Logger } from "../engine/Logger";

export class ShareHelper {

    public static init() {
        // let afdd:string = cc.url.raw("abcd")
        // Logger.log("afdd===", afdd)
        if (this.isWechatGame() || PlatformManager.onQQMiniGame) {
            // 显示当前页面的转发按钮
            wx.showShareMenu({
                success: (res) => {
                    Logger.log('开启被动转发成功！');
                },
                fail: (res) => {
                    Logger.log(res);
                    Logger.log('开启被动转发失败！');
                }
            })
            Logger.log("WechatHelper.init")
            wx.onShareAppMessage(() => {
                return {
                    title: '佣兵对战',
                    // imageUrl: cc.url.raw('img.png'),        // 分享图片要放在 wechatgame/res/raw-assets 路径下
                    // query: 'shareMsg='+'分享卡片上所带的信息'  // query最大长度(length)为2048
                }
            });
            // cc.url.raw()
        }

        if(PlatformManager.onQQMiniGame){
              // 显示当前页面的转发按钮
              wx.showShareMenu({
                success: (res) => {
                    Logger.log('开启被动转发成功！');
                },
                fail: (res) => {
                    Logger.log(res);
                    Logger.log('开启被动转发失败！');
                }
            })
            Logger.log("WechatHelper.init")
            wx.onShareAppMessage(() => {
                return {
                    title: '佣兵对战',
                    imageUrl: "https://guzuoresource.oss-cn-beijing.aliyuncs.com/df4-cocos/Operation/share_5.png",        // 分享图片要放在 wechatgame/res/raw-assets 路径下
                    // query: 'shareMsg='+'分享卡片上所带的信息'  // query最大长度(length)为2048
                }
            });
        }
    }


    /* 是否微信小游戏环境
    */
    public static isWechatGame() {
        return cc.sys.platform == cc.sys.WECHAT_GAME;
    }
}