
export default class RandomUtil {

    private seed: number = 0
    private static m = Math.pow(2,31)-1;

    public setSeed(seed: number) {
        this.seed = seed
    }

    public seedRandom(min: number = 0, max: number = 1) {
        this.seed = ((this.seed * 630360016 + 7) % RandomUtil.m).toRound(4);
        let rnd: number = this.seed / RandomUtil.m;
        return min + rnd * (max - min);
    }

    /** 随机minNum到maxNum的数字 （包含maxNum） */
    public nextInt(minNum: number, maxNum: number, useSeed: boolean = false) {
        if (useSeed) {
            return Math.floor(this.seedRandom() * (maxNum - minNum + 1) + minNum);
        } else {
            return Math.floor(Math.random() * (maxNum - minNum + 1) + minNum);
        }
    }

    public nextNumber(minNum: number, maxNum: number, useSeed: boolean = false) {
        if (useSeed) {
            return this.seedRandom() * (maxNum - minNum) + minNum;
        } else {
            return Math.random() * (maxNum - minNum) + minNum;
        }
    }

    public nextSign() {
        let temp = Math.random();
        if (temp < 0.5) {
            return 1
        }
        return -1;
    }

    public nextBoolean() {
        let temp = Math.random();
        if (temp < 0.5) {
            return true
        }
        return false;
    }

    public randomArr(nowArr: Array<any>, needNum: number): Array<any> {
        let tempArr: Array<any> = nowArr.concat();
        let resultArr: Array<any> = [];
        for (let index = 0; index < needNum; index++) {
            if (tempArr.length <= 0) {
                break;
            }
            let randomIndex: number = this.nextInt(0, tempArr.length - 1);
            resultArr.push(tempArr.splice(randomIndex, 1)[0]);
        }
        return resultArr;
    }

    public randomItem(nowArr: Array<any>) {
        return this.randomArr(nowArr, 1)[0];
    }

    public randomP(left: number, right: number, up: number, down: number) {
        let randomX: number = this.nextNumber(left, right)
        let randomY: number = this.nextNumber(up, down)
        return cc.v2(randomX, randomY)
    }

    public randomIndexByPercent(rateList: Array<number> = [100, 100, 100]) {
        let tempList: Array<number> = [];
        let totalTemp: number = 0;
        for (let i = 0; i < rateList.length; i++) {
            totalTemp += rateList[i];
            tempList[i] = totalTemp;
        }
        let randomTemp: number = this.nextInt(0, totalTemp);
        let resultIndex: number = tempList.length - 1;
        for (let i = 0; i < tempList.length; i++) {
            if (randomTemp <= tempList[i]) {
                resultIndex = i;
                break;
            }
        }
        return resultIndex;
    }



}
