export default class AdapterHelper {

    public static Init(){
        this.SetAdapter();
        this.OnCanvasResize();
    }

    public static OnCanvasResize(){
        cc.view.on("canvas-resize" , AdapterHelper.fixApdater , this);
    }

    public static OffCanvasResize(){
        cc.view.off("canvas-resize" , AdapterHelper.fixApdater , this);
    }

    protected static SetAdapter(){
        let visibleSize = cc.view.getVisibleSize();
        let designsize = cc.view.getDesignResolutionSize();
        let canvas: cc.Canvas[] = cc.director.getScene().getComponentsInChildren(cc.Canvas);
        let ratio: number = visibleSize.height / visibleSize.width;
        let designRatio: number = designsize.height / designsize.width;
        if (ratio >= designRatio) {
            canvas.forEach((value)=>{
                value.fitHeight = false;
                value.fitWidth = true;
            });
        } else {
            canvas.forEach((value)=>{
                value.fitHeight = true;
                value.fitWidth = false;
            });              
        }
    }

    public static fixApdater(){
        this.SetAdapter();
    }
}


