import BasePlatformAPI from "./BasePlatformAPI";

export interface GameRecorderManager {
    start(options?:StartOptions);
    onStart(callback : ()=>void);
    /** 记录精彩的视频片段，调用时必须是正在录屏，以调用时的录屏时刻为基准，指定前 x 秒，后 y 秒为将要裁剪的片段，可以多次调用，记录不同时刻。在结束录屏时，可以调用 clipVideo 接口剪辑并合成记录的片段。 */
    recordClip(options? : recordClipOptions) : number;
    /** 剪辑精彩的视频片段。 */
    clipVideo(options? : clipVideoOptions);
    pause();
    onPause(callback : ()=>void);
    resume();
    onResume(callback : ()=>void);
    stop();
    onStop(callback:(res : {videoPath : string})=>void);
    onError(callback:(res : {errMsg:string})=>void);
    /** 监听录屏中断开始事件。 */
    onInterruptionBegin(callback : ()=>void);
    /** 监听录屏中断结束。 */
    onInterruptionEnd(callback : ()=>void);
    getMark():{markWidth:number,markHeight:number};
}

export type StartOptions = {
    /** 录屏的时长，单位 s，必须大于 3s，最大值 300s（5 分钟）。 */
    duration?:number;
    /** 是否添加水印，会在录制出来的视频上添加默认水印，目前不支持自定义水印图案。 */
    isMarkOpen?:boolean;
    /** 水印距离屏幕上边界的位置，单位为 dp。 */
    locTop? : number;
    /** 水印距离屏幕左边界的位置，单位为 dp。 */
    locLeft? : number;
    /** 设置录屏帧率，对于性能较差的手机可以调低参数以降低录屏性能消耗。 */
    frameRate? : number;
}

export type recordClipOptions = {
    /** 数组的值表示记录这一时刻的前后时间段内的视频，单位是 s */
    timeRange? : number[];
    success? : Function;
    fail? : Function;
    complete? : Function;
}

export type clipVideoOptions = {
    /** path 的值为停止录屏拿到的视频地址 */
    path : string;
    /** 裁剪的范围，用法含义与recordClip 中的timeRange，完全相同，只是记录时相对的当前时刻规定为录屏结束时刻 */
    timeRange? : number[];
    /** 指定要裁剪的范围，数组中每一项为调用 recordClip 得到返回值 */
    clipRange? : number[];
    success? : (res : {videoPath : string})=>void;
    fail? : Function;
    complete? : Function;
}

export default class ByteRecorderAPI extends BasePlatformAPI {

    private static byterecorder : ByteRecorderAPI = null;
    public static get Init() : ByteRecorderAPI{
        if(this.byterecorder == null){
            this.byterecorder = new ByteRecorderAPI();
        }
        return this.byterecorder;
    }

    public getGameRecorderManager() : GameRecorderManager{
        if(!this.api) return null;
        return this.api.getGameRecorderManager();
    }
}