import DateUtil from "./DateUtil";

function getLogText(args: any[]){
	let text = ''
	for (let i = 0; i < args.length; i++) {
		let v = args[i];
		let type = typeof v;
		if (type == "number" || type == "string" || type == 'boolean') {
			text += ' ' + v;
		} else if(v instanceof Error){
			text += ' ' + v.message + v.stack;
		} else if (type == "object") {
			try { 
				let jsontext = JSON.stringify(v);
				if (jsontext.length > 500) jsontext = jsontext.substring(0,500)+'...'
				text += " OBJ->" + jsontext; 
			} catch (err) { 
				text += ' ' + type;
			}
		} else {
			text += ' ' + type;
		}
	}
	return text;
}

const _error = new Error();
function getStackTrace(func) {
	Error['captureStackTrace'] ? Error['captureStackTrace'](_error, func) : _error.stack = (new Error()).stack;
	return _error.stack;
}

const log = console.log;
const warn = console.warn;
const error = console.error;
export class DebugLogManager {
	public historyLogList: { logType: string, text: string}[] = [];
	public logList: { logType: string, text: string}[] = [];
	public errLogList: { logType: string, text: string}[] = [];
	public changeCallback: any;
	public warnCount: number = 0;
	public errorCount: number = 0;
	public enable: boolean = false;
	public enableAI: boolean = false;
	private debugPanel: cc.Node;
	private debugPrefab: cc.Prefab;
	private errorFileUrl: string; 
	private exceptionFileUrl : string;
	private exceptionFileText : string;
	private _oldCustomErrorLog: string;
	private _oldErrorLog: string;
	/** 记录登录前1秒内报错次数 */
	private _appStartErrorTime: number = 0;
	private _appStartErrorCount: number = 0;
	/** 记录上传报告日志 */
	private reports: {[key: string]: string[]} = {};

	constructor(){
		if(CC_EDITOR){
			return;
		}
		
		this.enableAI = cc.sys.localStorage.getItem('DebugLogEnableAi') == '1';
		
		window.onerror = this.onError.bind(this);

		if(CC_JSB){
			// 读取上次报错记录
			this.errorFileUrl = jsb.fileUtils.getWritablePath()+'error.log';
			this.exceptionFileUrl = jsb.fileUtils.getWritablePath()+'exception.log';
			this.readErrorLog();
		}
		
		// GameEventSystem.once(POST_LOGIN, this, this.onLogin)
	}
	
	/** 报错记录: 错误信息,出错的文件,出错代码的行号,出错代码的列号,错误的详细信息 */ 
	onError(errorMessage: string, scriptURI: string, lineNumber: string, columnNumber: string, errorObj: { stack: string; }){

		let stack_text = errorMessage + "\n错误文件:"+scriptURI+"\n行:"+lineNumber+"列:"+columnNumber +'\n'+ errorObj?.stack 
		// 记录本次错误内容, 避免死循环报错重复上传相同错误信息
		if (stack_text != this._oldErrorLog){
			this._oldErrorLog = stack_text;
	
			if(this.errLogList.length > 100){
				this.errLogList.splice(1,1);
			}
	
			// let text = "错误信息:" + "\n版本:v" + SingletonAttribute.config.app_version + " s" + SingletonAttribute.config.hot_version + '\n' + stack_text;
			let text = "错误信息:" + '\n' + stack_text;
			if(CC_JSB){
				this.errLogList.push({ logType: 'lastError', text: DateUtil.formateNow() +' '+ text });
				let reportText = this.getReport()
				reportText && console.warn(reportText)
				this.sendAppErrorReport(stack_text + '\n'+ reportText, '1')
				this.writeErrorLog();
			}
			this.onPrint('error', stack_text);
		}

		// 记录未登录前 1秒内报错次数超过15次自动清缓存并重启APP
		if(!this.isLogin()){
			let now = Date.now();
			let dt = now - this._appStartErrorTime;
			this._appStartErrorCount ++;
			// 统计1秒间隔内错误次数
			if(dt > 1000){
				if(this._appStartErrorCount > 15){
					window.onerror = ()=>{}
					console.error('异常重启: 错误过多,执行异常重启', this._appStartErrorCount, dt, this._appStartErrorTime);
					this.exceptionRestart();
				}
				this._appStartErrorCount = 0;
				this._appStartErrorTime = now;
			}
		}else{
			this._appStartErrorCount = 0;
		}

		// 修复部分玩家热更新资源错误错误
		if(stack_text.includes('UILoadSucc@assets/main/index')){
            // SceneAPI.Init.ShowToast("下载资源错误, 即将重启修复" , "none");
			this.exceptionRestart();
		}
	}

	/** 首次登录上报闪退记录 */
	onLogin(){
		if(!CC_JSB){
			return;
		}

		if(this.exceptionFileText && jsb.fileUtils.isFileExist(this.exceptionFileUrl)){
			this.appErrorReport(this.exceptionFileText, '2').then((res)=>{
				jsb.fileUtils.removeFile(this.exceptionFileUrl); // 上报成功删除文件
			})
		}
	}

	writeErrorLog(){
		let text = JSON.stringify(this.errLogList)
		jsb.fileUtils.writeStringToFile(text, this.errorFileUrl);
	}

	readErrorLog(){
		if(!CC_JSB) return;
		if(jsb.fileUtils.isFileExist(this.errorFileUrl)){
			let text = jsb.fileUtils.getStringFromFile(this.errorFileUrl);
			try{
				this.historyLogList = JSON.parse(text);
			}catch(e){
				console.error(e);
				this.historyLogList = [{logType:'lastError', text}];
			}
		}

		if(jsb.fileUtils.isFileExist(this.exceptionFileUrl)){
			this.exceptionFileText = jsb.fileUtils.getStringFromFile(this.exceptionFileUrl);
			console.error(this.exceptionFileText);
			this.historyLogList.push({logType:'lastError' , text: this.exceptionFileText});
		}
		return this.historyLogList;
	}

	startDebug(){
		if(this.enable){
			return;
		}
		this.enable = true;
		console.log = (...params)=>{
			log(...params)
			this.onPrint('log', getLogText(params))
		}

		console.warn = (...params) => {
			warn(...params)
			this.onPrint('warn', getLogText(params) + "\n" + getStackTrace(console.warn))
		}

		console.error = (...params) => {
			error(...params)

			if(typeof(params[0]) === 'string'){
				if(params[0].indexOf("unhandledRejectedPromise") != -1 || params[0].indexOf("handlerAddedAfterPromiseRejected") != -1){
					return;
				}
			}

			this.onPrint('warn', getLogText(params) + "\n" + getStackTrace(console.error))
		}
		if(!this.debugPrefab){
			cc.resources.load('view/logPanel/logPanel',cc.Prefab,(err, prefab)=>{
				if(!prefab){
					console.warn("startDebug: ",err)
					return;
				}
				this.debugPrefab = prefab;
				this.debugPanel = cc.instantiate(prefab);
				cc.director.getScene().addChild(this.debugPanel);
				console.warn('startDebug log面板1')
			})
		}else{
			this.debugPanel = cc.instantiate(this.debugPrefab);
			cc.director.getScene().addChild(this.debugPanel);
		}

		console.warn('startDebug log面板0')
		cc.sys.localStorage.setItem('DebugLogEnableBox', '1');
		cc.sys.localStorage.setItem('DebugLogEnableAi', this.enableAI ? '1' : '');
	}

	stopDebug(){
		this.enable = false;
		console.log = log;
		console.warn = warn;
		console.error = error;
		if(this.debugPanel){
			this.debugPanel.destroy();
		}
		cc.sys.localStorage.setItem('DebugLogEnableBox', '');
	}

	onPrint(logType: string, text: string){
		if(!this.enable){
			return;
		}

		if(logType == 'warn'){
			this.warnCount ++;
		}else if(logType == 'error'){
			this.errorCount ++;
		}
		
		if(this.logList.length > 1000){
			this.logList.splice(0,500);
		}
		this.logList.push({ logType, text });
		this.changeCallback && this.changeCallback(logType, text)
	}

	/**
	 * 上报错误
	 * @param error_lv 日志等级, 1.捕获的错误，2.手动埋点上报错误
	 * @param error 日志内容
	 * @returns 
	 */
    private sendAppErrorReport(error: string, error_lv: string = '2') {
		if(CC_DEBUG || !CC_JSB){
			return;
		}
		
		// let version = SingletonAttribute.config.app_version + "_" + SingletonAttribute.config.hot_version+' '+cc.sys.os;
        // return GamePostManager.SendPost("/api/user/appErrorReportV2", {uid: AccountSystem.Id || '0', role_id: ActorSystem.curActorId || '0', version, error_lv, error}, this, (res) => {
        //     return res.data;
        // });
    }
	
	/**
	 * 上报埋点错误
	 * @param error_lv 日志等级, 1.捕获的错误，2.手动埋点上报错误
	 * @param error 日志内容
	 * @returns 
	 */
    appErrorReport(error: string, error_lv: string = '2') {
		console.error('上报错误: ', error, error_lv);
		if(CC_DEBUG || !CC_JSB || error == this._oldCustomErrorLog){
			return;
		}
		// 记录本次错误内容, 避免死循环报错重复上传相同错误信息
		this._oldCustomErrorLog = error;
        return this.sendAppErrorReport(error, error_lv)
    }

	/**
	 * 添加准备上传的日志, 在报错时手动上传
	 * @param reportText 日志
	 * @param reportType 自定义日志类型, 方便同时跟踪不同问题, None类型是触发异常时自动上传
	 */
	addReport(reportText: string, reportType: string = 'None'){
		if(!CC_JSB || !reportText){
			return;
		}

		let list = this.reports[reportType];
		if(!list){
			this.reports[reportType] = list = [];
		}
		
		// 限制最大记录100条日志
		if(list.length > 100){
			list.splice(0,1);
		}
		list.push(reportText);
	}

	/**
	 * 获得报告文本
	 * @param reportType 自定义日志类型
	 * @param clearReport 获得报告文本后清除记录
	 */
	getReport(reportType: string = 'None', clearReport: boolean = true){
		if(!CC_JSB) return ''

		let list = this.reports[reportType];
		if(!list) return '' 
		let text = list.join("\n"); 
		clearReport && (list.length = 0);
		return text;
	}

	/**
	 * 清空报告记录
	 * @param reportType 
	 */
	clearReport(reportType: string = 'None'){
		this.reports[reportType] = null;
	}

	/** 用于异常重启 */
	exceptionRestart(){
		if(!CC_JSB){
			return;
		}
		// 清除所有热更以及其它缓存文件
		// let hot_dir = jsb.fileUtils.getWritablePath() + 'hot-update'
		cc.assetManager.cacheManager.clearCache();
		// SceneAPI.Init.ShowToast("游戏异常, 即将重启修复" , "none");
		console.warn('异常重启: 重置缓存结果:', 
			JsbFileToolsSystem.DeleteDir(jsb.fileUtils.getWritablePath())
		);
        cc.audioEngine.stopAll();
		cc.game.restart()
	}

	isLogin(){
		try{
			// return Singleton.AccountSystem.Token != null
		}catch(e){
			console.error(e);
			return false;
		}
	}

	Btn_CleanNativeFile(){
		console.error("确认框ui未加载, 无法清除缓存")
	}
}

export const DebugLogSystem = new DebugLogManager()

CC_DEBUG && (window['DebugLogSystem'] = DebugLogSystem)