import { DebugLogSystem } from "../DebugLogManager";
import { Logger } from "../Logger";

export const HTTP_COMPLETE = "http_complete";
export const HTTP_ERROR = "http_error";
export const HTTP_PROGRESS = "http_progress";

export default class HttpRequest extends cc.EventTarget{

    //example
    // HttpClient.instance.request("http://localhost:8080/haohttp/test", ()=>{
    //     console.log("http 请求 end=============");
    // }, {"nickName":"jhao", "hh":1, "id":9527});

    public methodType: string = "POST";
    public timeOut : number = 120000;
    public responseType: XMLHttpRequestResponseType = "json";
    public tryCount : number = 1;

    private xhr: XMLHttpRequest;

    private myRequestHeader: {[key : string] : string}
    private contentType: string = "application/x-www-form-urlencoded";
    private curCount : number;

    private is_setheader : boolean;

    constructor() {
        super();
        !CC_JSB && (this.xhr = new XMLHttpRequest());
        this.curCount = 0;
        this.is_setheader = false;
    }

    public setRequestHeader(key: string, value: string) {
        !this.myRequestHeader && (this.myRequestHeader = {});
        this.myRequestHeader[key] = value;
    }

    private resetRequestHeader() {
        this.myRequestHeader = null;
    }

    clear(): void {
        super.clear();
        this.clearHttp();
    }

    clearHttp(){
        this.is_setheader = false;
        this.xhr.onreadystatechange = this.xhr.onprogress = this.xhr.onerror = this.xhr.ontimeout = null;
    }

    public send(url: string , data : any) {
        let _data = data; 
        let xhr : XMLHttpRequest;

        if(!CC_JSB){            
            xhr = this.methodType == "POST" ? this.xhr : new XMLHttpRequest();
        }else{
            this.xhr && this.clearHttp();
            xhr = this.xhr = new XMLHttpRequest(); 
        }
        
        xhr.responseType != this.responseType && (xhr.responseType = this.responseType);
        xhr.timeout = this.timeOut;  
        xhr.onreadystatechange = () => {
            // Logger.info("http request======onreadystatechange", xhr.readyState, xhr.status , xhr);
            if (xhr.readyState == 4 && xhr.status == 200) {
                try {
                    let response;
                    if(CC_JSB){
                        response = xhr.responseType == "json" ? JSON.parse(xhr.responseText) : xhr.response;
                    }else{
                        response = xhr.response; 
                    }
                    // Logger.info("http request======onreadystatechange222", xhr.responseText);
                    // Logger.info("http request======onreadystatechange333", xhr.response); 
                    
                    // Logger.info("http request======response========", response);          
                    this.curCount != 0 && Logger.warn("http request======ontimeout重试成功========", url , "次数" , this.curCount , "总重试次数" , this.tryCount);
                    this.emit(HTTP_COMPLETE , response);
                    this.clear();
                    this.resetRequestHeader()
                }catch(e){
                    Logger.error("接收数据有误" , e.message , url); 
                    DebugLogSystem.appErrorReport("url:"+url+"\nresponse:"+xhr.responseText+"\nerr:"+JSON.stringify(e)+"\n已重试次数: "+this.curCount , "2");
                    this.curCount++;
                    !CC_JSB && xhr.open(this.methodType, url, true);
                    !CC_JSB && this.SetHeader(xhr , this.myRequestHeader);
                    this.send(url , _data);
                }
            } else if (xhr.readyState == 4 && xhr.status == 301) {//域名转移
                this.send(xhr.getResponseHeader("Location") , _data);
            }
            else if (xhr.readyState == 4 && xhr.status == 404) {
                this.curCount += 1;
                if(this.curCount < this.tryCount){
                    !CC_JSB && xhr.open(this.methodType, url, true);
                    !CC_JSB && this.SetHeader(xhr , this.myRequestHeader);
                    this.send(url , _data);
                }else{
                    this.emit(HTTP_ERROR , {msg : "404"});
                    this.clear();
                    this.resetRequestHeader()
                }                
            }
            else {                
                if (xhr.readyState == 4) {
                    this.curCount += 1;
                    if(this.curCount < this.tryCount){                        
                        !CC_JSB && xhr.open(this.methodType, url, true);
                        !CC_JSB && this.SetHeader(xhr , this.myRequestHeader);
                        this.send(url , _data);
                    }else{
                        this.emit(HTTP_ERROR , {msg:"unknow"});
                        this.clear();
                        this.resetRequestHeader()
                    }
                }
            }
        };
        xhr.onprogress = (e) => {
            if(e.lengthComputable){
                this.emit(HTTP_PROGRESS , e);
            }            
        }
        xhr.onerror = (e) => {
            Logger.warn("http request======error========", e);
            this.curCount += 1;
            if(this.curCount < this.tryCount){
                !CC_JSB && xhr.open(this.methodType, url, true);
                !CC_JSB && this.SetHeader(xhr , this.myRequestHeader);
                this.send(url , _data);
            }else{

                this.emit(HTTP_ERROR , e);
                this.clear();
                this.resetRequestHeader()
            }            
        }
        xhr.ontimeout = () => {            
            if(this.curCount < this.tryCount){
                this.curCount += 1;
                Logger.warn("http request======ontimeout========", url , "次数" , this.curCount , "总重试次数" , this.tryCount);
                !CC_JSB && xhr.open(this.methodType, url, true);
                !CC_JSB && this.SetHeader(xhr , this.myRequestHeader);
                this.send(url , _data);
            }else{
                DebugLogSystem.appErrorReport("timeout超时,url:"+url , "2");
                this.emit(HTTP_ERROR , {msg:"timeout"});
                this.clear();
                this.resetRequestHeader()
            }
        }
        if(CC_DEBUG && !url.includes('getTableData')){
            Logger.log('http',"request======url========", url , _data , this.methodType , this.contentType , this.myRequestHeader);
        }
        xhr.open(this.methodType, url, true);
        this.SetHeader(xhr , this.myRequestHeader);
        xhr.send(_data);        
    }

    private SetHeader(xhr : XMLHttpRequest , header : {[key : string] : string}){
        if(CC_JSB && this.is_setheader) return;
        if(this.methodType == "POST") { 
            xhr.setRequestHeader("content-type", this.contentType);
            if(this.myRequestHeader){
                for(let k in this.myRequestHeader){
                    xhr.setRequestHeader(k, this.myRequestHeader[k]);
                }
                // this.myRequestHeader.has("Authorization") && (xhr.setRequestHeader("Authorization" , this.myRequestHeader.get("Authorization")));
            }
        }
        this.is_setheader = true;
    }
}
